cat > /tmp/apicheck/Program.cs << 'CODE'
using System.Reflection;
using Microsoft.Extensions.AI;

// Look for FunctionInvoking or tool-related middleware
var meaiAsm = typeof(IChatClient).Assembly;
var types = meaiAsm.GetExportedTypes()
    .Where(t => t.Name.Contains("FunctionInvok") || t.Name.Contains("UseFunctionInvok") || t.Name.Contains("ChatClientBuilder"))
    .OrderBy(t => t.FullName);

foreach (var t in types)
{
    Console.WriteLine($"\n=== {t.FullName} ===");
    var methods = t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly);
    foreach (var m in methods.Take(20))
    {
        var pStr = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {(m.IsStatic ? "static " : "")}{m.ReturnType.Name} {m.Name}({pStr})");
    }
}

// Also check ChatClientBuilder extension methods
var extTypes = meaiAsm.GetExportedTypes().Where(t => t.IsAbstract && t.IsSealed && t.Name.Contains("Extension"));
