using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to your OpenAI API key.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new Notebook();
var webSearcher = new WebSearcher();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearcher.SearchAsync),
    AIFunctionFactory.Create(notebook.TakeNoteAsync),
    AIFunctionFactory.Create(notebook.GetNotesAsync),
};

// --- Chat client setup -------------------------------------------------------

var openAiClient = new OpenAIClient(apiKey);
IChatClient chatClient = openAiClient
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Agent setup -------------------------------------------------------------

const string instructions = """
    You are a research agent. When the user gives you a topic:
    1. Use the SearchWeb tool several times with different queries to gather
       information from multiple angles.
    2. As you find important facts, use TakeNote to record them with a short title.
    3. After you have gathered enough information (at least 3-5 notes), call
       GetNotes to review everything you've collected.
    4. Finally, write a well-structured summary of your findings, citing the
       sources you used.
    Be thorough but concise. Focus on factual, up-to-date information.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and taking notes",
    tools: tools);

// --- Run the agent -----------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (powered by AI)     ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

var session = await agent.CreateSessionAsync();

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Research complete. {notebook.Count} note(s) taken.");

// =============================================================================
// Tool implementations
// =============================================================================

/// <summary>Provides web search capabilities by fetching and extracting text from search results.</summary>
sealed partial class WebSearcher
{
    private static readonly HttpClient s_http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
    };

    [Description("Searches the web for information on a query and returns a summary of the top results.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

            var html = await s_http.GetStringAsync(url, cancellationToken);
            var text = ExtractTextFromHtml(html);

            // Trim to a reasonable size for the LLM context
            if (text.Length > 4000)
                text = text[..4000] + "\n[... results truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? $"No results found for \"{query}\"."
                : $"Search results for \"{query}\":\n{text}";
        }
        catch (Exception ex)
        {
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    private static string ExtractTextFromHtml(string html)
    {
        // Strip scripts and styles
        var cleaned = ScriptOrStyleRegex().Replace(html, " ");
        // Strip HTML tags
        cleaned = HtmlTagRegex().Replace(cleaned, " ");
        // Decode HTML entities
        cleaned = WebUtility.HtmlDecode(cleaned);
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();
        return cleaned;
    }

    [GeneratedRegex(@"<(script|style)[^>]*>[\s\S]*?</\1>", RegexOptions.IgnoreCase)]
    private static partial Regex ScriptOrStyleRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex HtmlTagRegex();

    [GeneratedRegex(@"\s{2,}")]
    private static partial Regex WhitespaceRegex();
}

/// <summary>An in-memory notebook for recording research findings.</summary>
sealed class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public int Count => _notes.Count;

    [Description("Saves a research note with a title and content. Use this to record important facts discovered during research.")]
    public Task<string> TakeNoteAsync(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content/body of the note with the facts to remember")] string content)
    {
        _notes.Add((title, content));

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        Console.ResetColor();

        return Task.FromResult($"Note #{_notes.Count} saved: \"{title}\"");
    }

    [Description("Retrieves all previously saved research notes. Call this before writing the final summary.")]
    public Task<string> GetNotesAsync()
    {
        if (_notes.Count == 0)
            return Task.FromResult("No notes have been taken yet.");

        Console.ForegroundColor = ConsoleColor.DarkGreen;
        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        Console.ResetColor();

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"\n--- Note #{i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
        }

        return Task.FromResult(sb.ToString());
    }
}

